function minDeletionsForAnagram(s1, s2) {
  const freq = {};

  for (const char of s1) {
    freq[char] = (freq[char] || 0) + 1;
  }

  for (const char of s2) {
    freq[char] = (freq[char] || 0) - 1;
  }

  return Object.values(freq).reduce((sum, val) => sum + Math.abs(val), 0);
}
